#include<bits/stdc++.h>
using namespace std;

int main(){
    int a,b,ans=0;
    cin>>a>>b;
    for(int i=a;i<=b;i++){
        long long x=i,num1=0,num2=0;
        bool flag=1;
        cin>>x;
        while(x){
            if(flag) num1+=x%10;
            else num2+=x%10;
            x/=10;
            flag=!flag;
        }
        if(num1==num2) ans++;
    }
    cout<<ans;
    return 0;
}
